// build.gradle:
//   implementation 'org.springframework.boot:spring-boot-starter-security'
//   implementation 'org.springframework.boot:spring-boot-starter-oauth2-resource-server'

// SecurityConfig.java
@Configuration
@EnableWebSecurity
@EnableMethodSecurity   // enables @PreAuthorize / @PostAuthorize
public class SecurityConfig {

  @Bean
  SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
    http
      // Disable CSRF for stateless REST API (JWT-based, not cookie-based)
      .csrf(csrf -> csrf.disable())

      // CORS from another file (or here)
      .cors(cors -> {})

      // No HTTP sessions — every request stands alone
      .sessionManagement(sm -> sm.sessionCreationPolicy(SessionCreationPolicy.STATELESS))

      // URL-level rules
      .authorizeHttpRequests(auth -> auth
        .requestMatchers("/actuator/health", "/api/v1/auth/**").permitAll()
        .requestMatchers("/api/v1/admin/**").hasRole("ADMIN")
        .requestMatchers(HttpMethod.GET, "/api/v1/**").hasAuthority("SCOPE_read")
        .requestMatchers(HttpMethod.POST, "/api/v1/**").hasAuthority("SCOPE_write")
        .anyRequest().authenticated())

      // JWT via OAuth2 Resource Server (the modern preferred way)
      .oauth2ResourceServer(oauth2 -> oauth2.jwt(jwt -> jwt.jwtAuthenticationConverter(jwtConverter())))

      .exceptionHandling(ex -> ex
        .authenticationEntryPoint((req, res, e) -> res.setStatus(401))
        .accessDeniedHandler((req, res, e) -> res.setStatus(403)));

    return http.build();
  }

  @Bean
  PasswordEncoder passwordEncoder() {
    return new BCryptPasswordEncoder();
  }

  private JwtAuthenticationConverter jwtConverter() {
    var converter = new JwtGrantedAuthoritiesConverter();
    converter.setAuthoritiesClaimName("scope");
    converter.setAuthorityPrefix("SCOPE_");

    var jwtConverter = new JwtAuthenticationConverter();
    jwtConverter.setJwtGrantedAuthoritiesConverter(converter);
    return jwtConverter;
  }
}

// application.yaml
// spring:
//   security:
//     oauth2:
//       resourceserver:
//         jwt:
//           issuer-uri: https://accounts.example.com    # OIDC issuer
//           # OR: jwk-set-uri: https://accounts.example.com/.well-known/jwks.json

// Method-level authorization on services
@Service
public class OrderService {

  @PreAuthorize("hasRole('ADMIN')")
  public void deleteAllOrders() { /* only admins */ }

  @PreAuthorize("hasAuthority('SCOPE_orders:write') && #order.userId == authentication.principal.userId")
  public Order create(Order order) {
    // SpEL expression: caller must have the scope AND the order must belong to them
    return repo.save(order);
  }

  @PostAuthorize("returnObject.userId == authentication.principal.userId")
  public Order getById(Long id) {
    return repo.findById(id).orElseThrow();
  }
}

// Custom AuthenticationPrincipal to access the JWT claims typed
public record AuthenticatedUser(String userId, String email, Set<String> scopes) {}

@GetMapping("/me")
public AuthenticatedUser me(@AuthenticationPrincipal Jwt jwt) {
  return new AuthenticatedUser(
    jwt.getSubject(),
    jwt.getClaim("email"),
    Set.copyOf(jwt.getClaim("scope") instanceof List<?> l ? l.stream().map(Object::toString).toList() : List.of()));
}

@Service
public class UserService {
  private final PasswordEncoder encoder;   // injected — BCryptPasswordEncoder
  private final UserRepository repo;

  public UserService(PasswordEncoder e, UserRepository r) { this.encoder = e; this.repo = r; }

  public User register(String email, String rawPassword) {
    var hashed = encoder.encode(rawPassword);   // one-way; slow on purpose (~100ms)
    return repo.save(new User(email, hashed));
  }

  public boolean checkPassword(User user, String rawPassword) {
    return encoder.matches(rawPassword, user.hashedPassword());
  }
}

// Never sha256, never md5. BCrypt (or Argon2 / scrypt) is designed to be SLOW —
// each guess takes ~100ms so brute-force attacks with rainbow tables are infeasible.
// Includes a per-user salt automatically. This is the #1 security decision you'll make.

